instruction = ("袛谢褟 薪邪褋褌褉芯泄泻懈 褋胁芯斜芯写薪芯谐芯 写芯褋褌褍锌邪 泻芯 胁褋械屑 褋械褉胁懈褋邪屑 薪械芯斜褏芯写懈屑芯 锌褉懈谢芯卸械薪懈械 懈 泻芯薪褎懈谐褍褉邪褑懈褟 褋 褋邪屑芯泄 谢芯泻邪褑懈械泄\n\n"
               "袧邪锌褉懈屑械褉, 胁褘斜褉邪谢 馃嚨馃嚤 Poland 懈 褟 锌褉械写芯褋褌邪胁谢褞 薪褍卸薪褍褞 泻芯薪褎懈谐褍褉邪褑懈褞, 泻芯褌芯褉褍褞 锌褉芯褋褌芯 薪褍卸薪芯 写芯斜邪胁懈褌褜 胁 褝褌芯 锌褉懈谢芯卸械薪懈械 - 'Happ' 写芯褋褌褍锌薪芯械 胁 Google Play 懈 AppStore")

text_link = "鉂楋笍小屑芯褌褉懈 袠袧小孝袪校袣笑袠挟鉂楋笍馃搶\n\n馃憠袧邪卸屑懈 薪邪 褋褋褘谢泻褍, 褔褌芯 斜褘 褋泻芯锌懈褉芯胁邪褌褜 懈 写芯斜邪胁褜 胁 锌褉懈谢芯卸械薪懈械\n\nANDROID/袩袣/iPhone/Mac - 'Happ' 胁 Google Play 懈 AppStore\n\n鉂楋笍袨写薪邪 褋褋褘谢泻邪 - 芯写薪芯 褍褋褌褉芯泄褋褌胁芯鉂楋笍"